import React, { createContext, useContext, useState, useEffect } from "react";

const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [loading, setLoading] = useState(true);

  // Simulated user database
  const userDatabase = {
    "test@university.edu": "password123",
    "alumni@example.com": "Alumni123",
  };

  // Load user from localStorage on mount
  useEffect(() => {
    const savedUser = localStorage.getItem("alumni_user");
    if (savedUser) {
      setUser(JSON.parse(savedUser));
      setIsAuthenticated(true);
    }
    setLoading(false);
  }, []);

  const login = async (email, password) => {
    try {
      setLoading(true);

      // Simulate API delay
      await new Promise((resolve) => setTimeout(resolve, 1000));

      // Validate credentials
      if (!userDatabase[email] || userDatabase[email] !== password) {
        return {
          success: false,
          message:
            "Invalid email or password. Try test@university.edu / password123",
        };
      }

      const newUser = {
        id: Date.now(),
        email,
        name:
          email.split("@")[0].charAt(0).toUpperCase() +
          email.split("@")[0].slice(1),
        avatar: "👤",
        graduationYear: "2020",
        company: "Tech Company",
        position: "Software Engineer",
        bio: "Passionate about technology and innovation",
        connections: 142,
        joinedDate: new Date().toISOString(),
        premium: false,
      };

      setUser(newUser);
      setIsAuthenticated(true);
      localStorage.setItem("alumni_user", JSON.stringify(newUser));

      return { success: true, message: "Login successful!" };
    } catch (error) {
      return { success: false, message: "Login failed. Please try again." };
    } finally {
      setLoading(false);
    }
  };

  const logout = () => {
    setUser(null);
    setIsAuthenticated(false);
    localStorage.removeItem("alumni_user");
  };

  const signup = async (email, password) => {
    try {
      setLoading(true);

      await new Promise((resolve) => setTimeout(resolve, 1000));

      if (userDatabase[email]) {
        return { success: false, message: "Email already registered" };
      }

      // Add new user to database (in real app, this would be backend)
      userDatabase[email] = password;

      const newUser = {
        id: Date.now(),
        email,
        name:
          email.split("@")[0].charAt(0).toUpperCase() +
          email.split("@")[0].slice(1),
        avatar: "👤",
        graduationYear: new Date().getFullYear().toString(),
        company: "Not specified",
        position: "Recent Graduate",
        bio: "Welcome to the Alumni Network!",
        connections: 0,
        joinedDate: new Date().toISOString(),
        premium: false,
      };

      setUser(newUser);
      setIsAuthenticated(true);
      localStorage.setItem("alumni_user", JSON.stringify(newUser));

      return { success: true, message: "Account created successfully!" };
    } catch (error) {
      return { success: false, message: "Signup failed. Please try again." };
    } finally {
      setLoading(false);
    }
  };

  const updateProfile = (updates) => {
    const updatedUser = { ...user, ...updates };
    setUser(updatedUser);
    localStorage.setItem("alumni_user", JSON.stringify(updatedUser));
  };

  return (
    <AuthContext.Provider
      value={{
        user,
        isAuthenticated,
        loading,
        login,
        logout,
        signup,
        updateProfile,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error("useAuth must be used within AuthProvider");
  }
  return context;
};
